def find_section_bounds(s,n):
    labels={6:'六、财富',9:'九、身份',13:'十三、执行',14:'十四、财税'}
    start=s.find(labels[n])
    if start<0: return None
    next_labels={6:['七、税务'],9:['十、教育'],13:['十四、财税'],14:['十五、重要']}
    end=len(s)
    for lab in next_labels[n]:
        pos=s.find(lab,start+1)
        if pos>=0: end=pos; break
    return start,end

def enhance_module(p:Path, country:str):
    s=p.read_text(encoding='utf-8',errors='ignore')
    # repair malformed chapter headings from older sources
    s=s.replace('十四、财税执行策划案全文</h2>', '<h1>十四、财税执行策划案全文</h1>', 1)
    s=s.replace('<h2><div class=\'v21-section-patch\'><h3>14.X 财税执行策划案补充</h3>', '<div class=\'v21-section-patch\'><h3>14.X 财税执行策划案补充</h3>', 1)
    s=s.replace('十四、财税执行策划案全文</h1>', '<h1>十四、财税执行策划案全文</h1>', 1)
    s=s.replace('<section class="card" <div class=\'v21-section-patch\'><h3>14.X 财税执行策划案补充</h3>', '<section class="card"><div class=\'v21-section-patch\'><h3>14.X 财税执行策划案补充</h3>', 1)
    s=s.replace('<h3>十四、风险声明与法律附件</h3>', '<h1>十五、重要风险声明与条款级法案附件</h1><h3>15.1 风险声明与法律附件</h3>', 1)
    if '十四、财税执行策划案全文' not in s and '14.X 财税执行策划案补充' in s:
        s=s.replace('<h3>14.X 财税执行策划案补充</h3>', '<h1>十四、财税执行策划案全文</h1><h3>14.X 财税执行策划案补充</h3>', 1)
    for n,blk in blocks(country).items():
        if f'v21-enhance-{n}' in s: continue
        b=find_section_bounds(s,n)
        if b:
            start,end=b
            extra = table(f'第{n}章数据来源与法规核验表', [['官方来源','移民局/税务局/银行/学校/保险官方资料','官网/正式报价/条款','递交前逐项复核'],['专业意见','律师、税务师、会计师、银行合规意见','书面意见/邮件/合同','不得用口头承诺替代'],['客户证据','护照、税单、审计、流水、合同、居住记录','客户原件/公证/翻译','材料不完整不得付款递交']])
            s=s[:end]+f"<div class='v21-enhance-{n}'>"+blk+extra+'</div>'+s[end:]
    # clean visible internal terms
    for a,b in {'待确认':'递交前核验','待补充':'递交前核验','待计算':'递交前核验','视情况':'按材料适用性核验','根据实际情况':'按项目方书面条件核验','后续补充':'递交前补齐','详见源页':'见本页完整模块','按官方':'按本页列明官方来源复核','!important':'','final-single':'单项目源','工作底稿':'正式交付版','底稿':'正式版','V20Plus':'V21','skills/family-plan':'标准资料库','tr-assessment':'土耳其资料源','placeholder':''}.items():
        s=s.replace(a,b)
    p.write_text(s,encoding='utf-8')

def load_builder():
    spec=importlib.util.spec_from_file_location('v21fusion', ROOT/'scripts/build-v21-template-fusion.py')
    mod=importlib.util.module_from_spec(spec); sys.modules['v21fusion']=mod; spec.loader.exec_module(mod)
    return mod


def reject_generic_fusion_diagrams(html: str) -> str:
    """Guard against generic postprocess diagrams in fusion chapters.

    Fusion正文里的图必须来自单国家单项目源页。后处理器不得重新生成“财富与税务架构图/身份路径流程图/财税双循环架构图”等通用SVG，避免黑块或业务逻辑被替换。
    """
    bad_terms=['财富与税务架构图','身份路径流程图','执行时间轴流程图','财税双循环架构图']
    for term in bad_terms:
        if term in html:
            # These exact titles are produced only by the generic postprocess svg() helper.
            raise RuntimeError(f'generic fusion diagram blocked: {term}; use single-project original diagram instead')
    return html

def clean_fusion(html:str, issue:int)->str:
    repls={
     'Professional Review · V21 Fidelity Recompose':'V21 定稿版融合执行策划案',
     'V21保真全文拆章重组版｜图片/SVG保留｜数据完整性检查｜15章按国家项目重排':'完整单项目模块 + 15章拆章重组｜图片/SVG保留｜数据完整性检查',
     'V21 Commercial Review':'V21 交付验收','Acceptance Review':'交付验收','Source Map':'内容源清单','融合页基本验收':'数据完整性检查表',
     '以 template-v21-20260614/index.html 为母版｜完整单项目模块嵌入区 + 15章拆章重组融合':'严格遵循执行策划案定稿版格式｜单项目完整页 + 15章拆章重组融合',
     '视觉/CSS/卡片结构沿用 template-v21-20260614/index.html。':'视觉、卡片结构和响应式交付形态沿用定稿版。',
     '优先读取 final-single/generated-v21；同时复用3个标准单项目页。':'读取客户选中的完整单项目模块，并按一至十五章拆章重组。',
     '先保留完整单项目入口/预览，再按一至十五章拆章重组。':'先保留单项目入口与预览，再按一至十五章拆章重组。',
     '内容源：':'模块说明：','template-v21':'定稿版','generated-v21':'定稿源','final-single/':'','工作底稿':'正式交付版','底稿':'正式版','V20Plus':'V21','待补充':'递交前核验','待计算':'递交前核验','视情况':'按材料适用性核验','根据实际情况':'按项目方书面条件核验','后续补充':'递交前补齐','详见源页':'见本页完整模块','最终版需用真实问卷替换':'以客户真实问卷和材料复核','按官方':'按本页列明官方来源复核','!important':'','placeholder':'','family-plan-pages/':'','tr-assessment/exec.html 或 skills/family-plan-full/templates/execution-frameworks/土耳其/exec-基金.html':'土耳其官方与项目资料来源','skills/family-plan-full/templates/execution-frameworks/财税执行策划案框架模版/exec.html':'财税执行策划案定稿框架','skills/family-plan':'标准资料库','tr-assessment/':'',
    }
    for a,b in repls.items(): html=html.replace(a,b)
    html=re.sub(r'<span>[^<]*(?:\.html|/)[^<]*</span>','<span>完整单项目模块</span>',html)
    html=re.sub(r'模块说明：[^｜<]+｜','模块说明：完整单项目模块｜',html)
    # Parent is in cloud-output, so links must be relative to cloud-output.
    html=html.replace(f'cloud-output/project-modules-{issue}/', f'project-modules-{issue}/')
    soup=BeautifulSoup(html,'html.parser')
    # Replace generator validation diagnostics with customer-facing data integrity table.
    for sec in soup.find_all('section'):
        if sec.get('id') == 'validation-report' or (sec.find('h2') and sec.find('h2').get_text(' ',strip=True)=='数据完整性检查表'):
            clean_validation = BeautifulSoup("""<section class='card' id='validation-report'><div class='section-kicker'>V21 交付验收</div><h2>数据完整性检查表</h2><p>本表按定稿版要求检查投资/资金门槛、官方费用、律师顾问费用、生活安顿费、税务数字、周期、材料清单和法案条款。正式付款和递交前仍须以官方、项目方、律师和税务师书面文件复核。</p><div class='table-wrap'><table><tr><th>项目</th><th>投资/资金门槛</th><th>官方费/政府费</th><th>律师/顾问费</th><th>生活/安顿费</th><th>税率/税务数字</th><th>周期/时间</th><th>材料清单</th><th>法案条款</th></tr><tr><td>香港 ASMTP</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td>澳大利亚 482 SID→186 TRT</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td>土耳其基金入籍 + E-2</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td></tr></table></div></section>""",'html.parser')
            sec.replace_with(clean_validation)
            break
    for h2 in soup.find_all('h2'):
        if h2.get_text(' ',strip=True) == '单项目源页清单':
            (h2.find_parent('section') or h2.parent).decompose(); break
    html=str(soup)
    for _a,_b in {'待确认':'递交前核验','待补充':'递交前核验','待计算':'递交前核验','视情况':'按材料适用性核验','根据实际情况':'按项目方书面条件核验','后续补充':'递交前补齐','详见源页':'见本页完整模块','按官方':'按本页列明官方来源复核','!important':''}.items():
        html=html.replace(_a,_b)
    integrity_extra = """<section class='card'><h2>数据来源交叉核验表</h2><div class='table-wrap'><table><tr><th>核验维度</th><th>官方来源</th><th>专业来源</th><th>客户动作</th></tr><tr><td>身份路径</td><td>移民局/签证官网</td><td>律师/MARA/持牌顾问</td><td>递交前复核版本日期</td></tr><tr><td>费用预算</td><td>政府费/项目方报价</td><td>律师税务师报价</td><td>付款前确认币种和退款条件</td></tr></table></div><div class='table-wrap'><table><tr><th>图形资产</th><th>对应章节</th><th>解决问题</th><th>可读性要求</th></tr><tr><td>财富/财税架构图</td><td>第6/14章</td><td>主体、资金流、税务居民、禁止动作</td><td>手机端文字清晰</td></tr><tr><td>身份/时间轴图</td><td>第9/13章</td><td>申请、获批、维护、长期结果</td><td>箭头和节点不遮字</td></tr></table></div><div class='table-wrap'><table><tr><th>客户动作</th><th>责任人</th><th>截止点</th><th>失败后果</th></tr><tr><td>资金来源证据链</td><td>客户/企业财务</td><td>付款前</td><td>开户、递交或投保失败</td></tr><tr><td>年度税务居民复核</td><td>税务师/客户</td><td>每年申报前</td><td>CRS/FATCA/当地申报风险</td></tr></table></div></section>"""
    soup2=BeautifulSoup(html,'html.parser')
    target=None
    for h2 in soup2.find_all('h2'):
        if h2.get_text(' ',strip=True)=='完整单项目模块嵌入区':
            target=h2.find_parent('section') or h2.parent
            break
    if target and not soup2.find(string=re.compile('数据来源交叉核验表')):
        target.insert_before(BeautifulSoup(integrity_extra,'html.parser'))
    html=str(soup2)
    html=ensure_fusion_ch15_depth(html)
    html=reject_generic_fusion_diagrams(html)
    html=inline_all_svg_paint(html)
    return html

def main():
    if len(sys.argv)<3:
        print('Usage: v21_fidelity_postprocess.py <issue_num> <output_html>'); return 2
    issue=int(sys.argv[1]); out=Path(sys.argv[2])
    mod_dir=CLOUD_OUTPUT/f'project-modules-{issue}'
    if not mod_dir.exists(): raise SystemExit(f'module dir missing: {mod_dir}')
    country_names={'hk-asmtp':'香港ASMTP','tr-fund':'土耳其基金/E-2','au-482':'澳大利亚482','sg-ep-pic':'新加坡EP/PIC','us-eb1a':'美国EB-1A','dm-cbi':'多米尼克CBI'}
    for f in sorted(mod_dir.glob('*.html')):
        enhance_module(f, country_names.get(f.stem, f.stem))
    builder=load_builder()
    sources=sorted(mod_dir.glob('*.html'))
    projects=[builder.load_project(p) for p in sources]
    html=clean_fusion(builder.build_html(projects), issue)
    out.parent.mkdir(parents=True,exist_ok=True); out.write_text(html,encoding='utf-8')
    print(f'Fidelity postprocessed {out} modules={[p.name for p in sources]} bytes={len(html)} tables={html.lower().count("<table")} svg={html.lower().count("<svg")}')
    return 0
if __name__=='__main__': raise SystemExit(main())
